 1→import { useQuery } from '@tanstack/react-query';
 2→import { getMyStories, getStoryById, getChapter } from '../../../../API/StoryApi';
 3→
 4→export const useMyStories = (token) => {
 5→    return useQuery({
 6→        queryKey: ['myStories'],
 7→        queryFn: () => getMyStories(token),
 8→        enabled: !!token,
 9→        staleTime: 30000,
10→        refetchOnWindowFocus: false,
11→    });
12→};
13→
14→export const useStoryDetail = (storyId, token) => {
15→    return useQuery({
16→        queryKey: ['story', storyId],
17→        queryFn: () => getStoryById(storyId, token),
18→        enabled: !!storyId,
19→        staleTime: 30000,
20→        refetchOnWindowFocus: false,
21→    });
22→};
23→
24→export const useChapter = (storyId, chapterId, token) => {
25→    return useQuery({
26→        queryKey: ['chapter', storyId, chapterId],
27→        queryFn: () => getChapter(storyId, chapterId, token),
28→        enabled: !!storyId && !!chapterId,
29→        staleTime: 60000,
30→        refetchOnWindowFocus: false,
31→    });
32→};
