  1→import { useMutation, useQueryClient } from '@tanstack/react-query';
  2→import {
  3→    createStory,
  4→    updateStory,
  5→    deleteStory,
  6→    createChapter,
  7→    updateChapter,
  8→    deleteChapter,
  9→    reorderChapters,
 10→    toggleStoryVote,
 11→    toggleStoryLibrary,
 12→} from '../../../../API/StoryApi';
 13→
 14→export const useCreateStory = (token) => {
 15→    const queryClient = useQueryClient();
 16→    return useMutation({
 17→        mutationFn: (formData) => createStory(token, formData),
 18→        onSuccess: () => {
 19→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 20→        },
 21→    });
 22→};
 23→
 24→export const useUpdateStory = (token) => {
 25→    const queryClient = useQueryClient();
 26→    return useMutation({
 27→        mutationFn: ({ storyId, formData }) => updateStory(token, storyId, formData),
 28→        onSuccess: (_data, { storyId }) => {
 29→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 30→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 31→        },
 32→    });
 33→};
 34→
 35→export const useDeleteStory = (token) => {
 36→    const queryClient = useQueryClient();
 37→    return useMutation({
 38→        mutationFn: (storyId) => deleteStory(token, storyId),
 39→        onSuccess: () => {
 40→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 41→        },
 42→    });
 43→};
 44→
 45→export const useCreateChapter = (token) => {
 46→    const queryClient = useQueryClient();
 47→    return useMutation({
 48→        mutationFn: ({ storyId, title }) => createChapter(token, storyId, title),
 49→        onSuccess: (_data, { storyId }) => {
 50→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 51→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 52→        },
 53→    });
 54→};
 55→
 56→export const useUpdateChapter = (token) => {
 57→    const queryClient = useQueryClient();
 58→    return useMutation({
 59→        mutationFn: ({ storyId, chapterId, data }) => updateChapter(token, storyId, chapterId, data),
 60→        onSuccess: (_data, { storyId, chapterId }) => {
 61→            queryClient.invalidateQueries({ queryKey: ['chapter', storyId, chapterId] });
 62→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 63→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 64→        },
 65→    });
 66→};
 67→
 68→export const useDeleteChapter = (token) => {
 69→    const queryClient = useQueryClient();
 70→    return useMutation({
 71→        mutationFn: ({ storyId, chapterId }) => deleteChapter(token, storyId, chapterId),
 72→        onSuccess: (_data, { storyId }) => {
 73→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 74→            queryClient.invalidateQueries({ queryKey: ['myStories'] });
 75→        },
 76→    });
 77→};
 78→
 79→export const useReorderChapters = (token) => {
 80→    const queryClient = useQueryClient();
 81→    return useMutation({
 82→        mutationFn: ({ storyId, chapterOrder }) => reorderChapters(token, storyId, chapterOrder),
 83→        onSuccess: (_data, { storyId }) => {
 84→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
 85→        },
 86→    });
 87→};
 88→
 89→export const useToggleVote = (token) => {
 90→    const queryClient = useQueryClient();
 91→    return useMutation({
 92→        mutationFn: (storyId) => toggleStoryVote(token, storyId),
 93→        onMutate: async (storyId) => {
 94→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
 95→            const previous = queryClient.getQueryData(['story', storyId]);
 96→            if (previous) {
 97→                queryClient.setQueryData(['story', storyId], (old) => ({
 98→                    ...old,
 99→                    has_voted: !old.has_voted,
100→                    vote_count: old.has_voted ? (old.vote_count || 1) - 1 : (old.vote_count || 0) + 1,
101→                }));
102→            }
103→            return { previous };
104→        },
105→        onError: (_err, storyId, context) => {
106→            if (context?.previous) {
107→                queryClient.setQueryData(['story', storyId], context.previous);
108→            }
109→        },
110→        onSettled: (_data, _err, storyId) => {
111→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
112→        },
113→    });
114→};
115→
116→export const useToggleLibrary = (token) => {
117→    const queryClient = useQueryClient();
118→    return useMutation({
119→        mutationFn: (storyId) => toggleStoryLibrary(token, storyId),
120→        onMutate: async (storyId) => {
121→            await queryClient.cancelQueries({ queryKey: ['story', storyId] });
122→            const previous = queryClient.getQueryData(['story', storyId]);
123→            if (previous) {
124→                queryClient.setQueryData(['story', storyId], (old) => ({
125→                    ...old,
126→                    in_library: !old.in_library,
127→                }));
128→            }
129→            return { previous };
130→        },
131→        onError: (_err, storyId, context) => {
132→            if (context?.previous) {
133→                queryClient.setQueryData(['story', storyId], context.previous);
134→            }
135→        },
136→        onSettled: (_data, _err, storyId) => {
137→            queryClient.invalidateQueries({ queryKey: ['story', storyId] });
138→        },
139→    });
140→};
