  6→export const createStory = async (token, formData) => {
  7→    const headers = {};
  8→    if (token) headers['Authorization'] = `Bearer ${token}`;
  9→
 10→    const response = await apiRequest(`${BASE_URL}/stories`, {
 11→        method: 'POST',
 12→        headers,
 13→        body: formData,
 14→    });
 15→    if (!response.ok) {
 16→        const err = await response.json().catch(() => ({}));
 17→        throw new Error(err?.error || 'failed to create story');
 18→    }
 19→    return response.json();
 20→};
