 22→export const getStories = async (limit = 10, before = null, status = null, tag = null, token = null) => {
 23→    const params = new URLSearchParams();
 24→    params.set('limit', limit);
 25→    if (before) params.set('before', before);
 26→    if (status) params.set('status', status);
 27→    if (tag) params.set('tag', tag);
 28→
 29→    const headers = {};
 30→    if (token) headers['Authorization'] = `Bearer ${token}`;
 31→
 32→    const response = await apiRequest(`${BASE_URL}/stories?${params}`, {
 33→        method: 'GET',
 34→        headers,
 35→    });
 36→    if (!response.ok) {
 37→        const err = await response.json().catch(() => ({}));
 38→        throw new Error(err?.error || 'failed to fetch stories');
 39→    }
 40→    return response.json();
 41→};
