119→// ── Chapters ──
120→
121→export const createChapter = async (token, storyId, title) => {
122→    const headers = { 'Content-Type': 'application/json' };
123→    if (token) headers['Authorization'] = `Bearer ${token}`;
124→
125→    const response = await apiRequest(`${BASE_URL}/stories/${storyId}/chapters`, {
126→        method: 'POST',
127→        headers,
128→        body: JSON.stringify({ title }),
