 1→const formatPostDate = (dateString) =>{
 2→    const date = new Date(dateString);
 3→    const now = new Date();
 4→
 5→    const diffInSecs = Math.floor((now - date) / 1000);
 6→
 7→    if(diffInSecs < 86400){ // 86400 seconds = 24 hours
 8→        if(diffInSecs < 60) return 'Just now';
 9→
10→        const minutes = Math.floor(diffInSecs / 60);
11→
12→        if(minutes < 60) return `${minutes}mins ago`;
13→
14→        const hour = Math.floor(minutes / 60);
15→
16→        return `${hour} hours ago`;
17→    }
18→
19→    return date.toLocaleDateString('en-Us', {
20→        day: 'numeric',
21→        month: 'short',
22→        year: 'numeric'
23→    })
24→
25→
26→}
27→
28→export default formatPostDate;

 1→const slugifyTitle = (value = "") => {
 2→    return String(value)
 3→        .toLowerCase()
 4→        .trim()
 5→        .replace(/[^a-z0-9\s-]/g, "")
 6→        .replace(/\s+/g, "-")
 7→        .replace(/-+/g, "-")
 8→        .replace(/^-|-$/g, "");
 9→}
