190→    }
191→
192→    const insertData = {
193→        chapter_id: chapterId,
194→        user_id: userId,
195→        comment: comment.trim(),
196→        paragraph_index: paragraphIndex !== undefined ? parseInt(paragraphIndex) : -1,
197→        paragraph_fingerprint: paragraphFingerprint || null,
198→        parent_id: parentId || null,
199→    };
200→
201→    const { data, error } = await supabase
202→        .from('story_comments')
203→        .insert(insertData)
204→        .select(`*, users(id, name, image_url, username, badge)`)
205→        .single();
206→
207→    if (error) {
