### Part 5: Integration into ChapterReader

**File: `C:\Users\johnm\iskrib_v3\client\src\components\Stories\ChapterReader\ChapterReader.jsx`**

Modifications to the main component:

1. Add a `ref` to the `.chapter-reader-body` div
2. Add state for the active paragraph panel: `const [activeComment, setActiveComment] = useState(null)` -- stores `{ paragraphIndex, fingerprint, text }`
3. Fetch comment counts: `const { data: commentCounts } = useChapterCommentCounts(chapterId, token)`
4. Render `ParagraphCommentLayer` inside `.chapter-reader-body` (after the `LexicalComposer`)
5. Render `CommentPanel` via `AnimatePresence` when `activeComment` is non-null

```jsx
// Inside ChapterReader component, new state and refs:
const bodyRef = useRef(null);
const [activeComment, setActiveComment] = useState(null);

const { data: commentCounts } = useChapterCommentCounts(chapterId, token);

const handleParagraphClick = useCallback((index, fingerprint) => {
    // Get paragraph text for preview
    const el = bodyRef.current?.querySelector(`[data-paragraph-index="${index}"]`);
    const text = el?.textContent || '';
    setActiveComment({ paragraphIndex: index, fingerprint, text });
}, []);

// In the JSX, modify the body section:
<div className="chapter-reader-body" ref={bodyRef}>
    <LexicalComposer initialConfig={editorConfig}>
        <ReaderContent chapter={chapter} />
    </LexicalComposer>
    <ParagraphCommentLayer
        containerRef={bodyRef}
        commentCounts={commentCounts || {}}
        onParagraphClick={handleParagraphClick}
    />
</div>

// After the nav section, add the panel:
<AnimatePresence>
    {activeComment && (
        <CommentPanel
            chapterId={chapterId}
            paragraphIndex={activeComment.paragraphIndex}
            paragraphFingerprint={activeComment.fingerprint}
            paragraphText={activeComment.text}
            onClose={() => setActiveComment(null)}
            token={token}
        />
    )}
</AnimatePresence>
```

